import unreal
abp='/Game/Character/ABP_Bodycam'
unreal.load_asset(abp)
seq=None
for o in unreal.ObjectIterator():
    try:
        cls=o.get_class().get_name()
    except Exception:
        continue
    if cls=='AnimGraphNode_SequencePlayer' and ':AnimGraph.' in o.get_path_name() and 'ABP_Bodycam' in o.get_path_name() and '.Walk.' in o.get_path_name():
        seq=o
props = seq.get_editor_property('show_pin_for_properties')
print('PlayRate shown now:', [(str(p.get_editor_property('property_name')), p.get_editor_property('show_pin')) for p in props if 'PlayRate'==str(p.get_editor_property('property_name'))])
# pin objects on the ed graph node directly
try:
    print('NODE PINS RAW:', [str(pn) for pn in seq.get_editor_property('pins')])
except Exception as e:
    print('pins raw err', e)
